<description>Replace static waveform with a professional, dynamic rounded-bar visualization engine with smooth animations and responsive resizing.</description>
<content><![CDATA[
import React, { useRef, useEffect, useMemo, useState } from 'react';

interface WaveformProps {
    buffer: AudioBuffer | null;
    currentTime: number;
    isPlaying: boolean;
    onSeek: (time: number) => void;
    theme: 'light' | 'dark';
}

export const Waveform: React.FC<WaveformProps> = ({ buffer, currentTime, isPlaying, onSeek, theme }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [hoverX, setHoverX] = useState<number | null>(null);
    const [containerWidth, setContainerWidth] = useState(0);

    // Resize Observer to handle responsive width
    useEffect(() => {
        if (!containerRef.current) return;
        const observer = new ResizeObserver(entries => {
            for (const entry of entries) {
                setContainerWidth(entry.contentRect.width);
            }
        });
        observer.observe(containerRef.current);
        return () => observer.disconnect();
    }, []);

    // Process audio data into smoothed peaks
    const peaks = useMemo(() => {
        if (!buffer || containerWidth === 0) return null;

        const channels = buffer.numberOfChannels;
        const data = buffer.getChannelData(0);
        const len = data.length;

        // Bar density configuration
        const barWidth = 4;
        const barGap = 2;
        const totalBarWidth = barWidth + barGap;
        const barCount = Math.floor(containerWidth / totalBarWidth);
        const samplesPerBar = Math.floor(len / barCount);

        const calculatedPeaks = [];

        for (let i = 0; i < barCount; i++) {
            const start = i * samplesPerBar;
            const end = Math.min(start + samplesPerBar, len);
            let sum = 0;

            // RMS calculation for smoother visual
            for (let j = start; j < end; j++) {
                sum += data[j] * data[j];
            }
            const rms = Math.sqrt(sum / (end - start));

            // Non-linear scaling to boost quiet parts
            const val = Math.pow(rms, 0.7); 
            calculatedPeaks.push(Math.min(1, val * 1.5)); // Slight gain boost
        }
        return calculatedPeaks;
    }, [buffer, containerWidth]);

    // Draw the waveform
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas || !containerRef.current) return;

        const ctx = canvas.getContext('2d', { alpha: true });
        if (!ctx) return;

        const dpr = window.devicePixelRatio || 1;
        const rect = containerRef.current.getBoundingClientRect();
        const width = rect.width;
        const height = rect.height;

        canvas.width = width * dpr;
        canvas.height = height * dpr;
        ctx.scale(dpr, dpr);
        canvas.style.width = `${width}px`;
        canvas.style.height = `${height}px`;

        ctx.clearRect(0, 0, width, height);

        // Empty State
        if (!peaks || !buffer) {
            ctx.beginPath();
            ctx.moveTo(0, height / 2);
            ctx.lineTo(width, height / 2);
            ctx.strokeStyle = theme === 'dark' ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.05)';
            ctx.lineWidth = 2;
            ctx.setLineDash([4, 6]);
            ctx.stroke();
            return;
        }

        const barWidth = 4;
        const barGap = 2;
        const totalBarWidth = barWidth + barGap;
        const centerY = height / 2;

        // Colors
        const primaryColorStart = theme === 'dark' ? '#6366F1' : '#4F46E5'; // Indigo
        const primaryColorEnd = theme === 'dark' ? '#A855F7' : '#818CF8';   // Purple/Light Indigo
        const inactiveColor = theme === 'dark' ? 'rgba(255, 255, 255, 0.15)' : 'rgba(0, 0, 0, 0.1)';
        const playedColor = theme === 'dark' ? '#FFFFFF' : '#312E81';

        // Gradient for active waveform
        const gradient = ctx.createLinearGradient(0, 0, 0, height);
        gradient.addColorStop(0, primaryColorStart);
        gradient.addColorStop(1, primaryColorEnd);

        const progressRatio = currentTime / buffer.duration;
        const progressX = progressRatio * width;

        peaks.forEach((peak, index) => {
            const x = index * totalBarWidth;
            if (x > width) return;

            // Amplitude Height
            const barHeight = Math.max(4, peak * height * 0.8);
            const y = centerY - barHeight / 2;
            const radius = barWidth / 2;

            ctx.beginPath();

            // Draw smooth rounded rect manually for better browser support
            ctx.moveTo(x + radius, y);
            ctx.lineTo(x + barWidth - radius, y);
            ctx.quadraticCurveTo(x + barWidth, y, x + barWidth, y + radius);
            ctx.lineTo(x + barWidth, y + barHeight - radius);
            ctx.quadraticCurveTo(x + barWidth, y + barHeight, x + barWidth - radius, y + barHeight);
            ctx.lineTo(x + radius, y + barHeight);
            ctx.quadraticCurveTo(x, y + barHeight, x, y + barHeight - radius);
            ctx.lineTo(x, y + radius);
            ctx.quadraticCurveTo(x, y, x + radius, y);
            ctx.closePath();

            // Fill Logic: Past vs Future
            if (x < progressX) {
                // Already played
                ctx.fillStyle = gradient; 
                ctx.globalAlpha = 1.0;
            } else {
                // Not played yet
                ctx.fillStyle = inactiveColor;
                ctx.globalAlpha = 1.0;
            }
            ctx.fill();
        });

        // Draw Playhead Cursor
        if (buffer) {
            ctx.beginPath();
            ctx.moveTo(progressX, 0);
            ctx.lineTo(progressX, height);
            ctx.strokeStyle = playedColor;
            ctx.lineWidth = 2;
            ctx.shadowColor = theme === 'dark' ? 'rgba(99, 102, 241, 0.5)' : 'rgba(79, 70, 229, 0.3)';
            ctx.shadowBlur = 4;
            ctx.stroke();
            ctx.shadowBlur = 0;

            // Playhead Knob
            ctx.beginPath();
            ctx.arc(progressX, height - 6, 3, 0, Math.PI * 2);
            ctx.fillStyle = playedColor;
            ctx.fill();
        }

        // Hover Effect
        if (hoverX !== null) {
            ctx.beginPath();
            ctx.moveTo(hoverX, 0);
            ctx.lineTo(hoverX, height);
            ctx.strokeStyle = theme === 'dark' ? 'rgba(255,255,255,0.3)' : 'rgba(0,0,0,0.3)';
            ctx.lineWidth = 1;
            ctx.setLineDash([2, 2]);
            ctx.stroke();
            ctx.setLineDash([]);
        }

    }, [peaks, buffer, currentTime, theme, hoverX, containerWidth]);

    const handleMouseMove = (e: React.MouseEvent) => {
        if (!containerRef.current) return;
        const rect = containerRef.current.getBoundingClientRect();
        setHoverX(e.clientX - rect.left);
    };

    const handleMouseLeave = () => setHoverX(null);

    const handleClick = (e: React.MouseEvent) => {
        if (!buffer || !containerRef.current) return;
        const rect = containerRef.current.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const ratio = Math.max(0, Math.min(1, x / rect.width));
        const time = ratio * buffer.duration;
        onSeek(time);
    };

    return (
        <div 
            ref={containerRef} 
            className="w-full h-36 relative group cursor-pointer select-none bg-slate-100/50 dark:bg-black/20 rounded-2xl overflow-hidden border border-slate-200 dark:border-white/5 transition-all duration-300 hover:border-indigo-200 dark:hover:border-indigo-500/20"
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            onClick={handleClick}
        >
             <canvas 
                ref={canvasRef}
                className="w-full h-full block"
            />
            {!buffer && (
                <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none opacity-40">
                    <div className="flex gap-1 h-8 items-end mb-2">
                        <div className="w-1.5 h-3 bg-slate-400 dark:bg-slate-500 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                        <div className="w-1.5 h-6 bg-slate-400 dark:bg-slate-500 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                        <div className="w-1.5 h-4 bg-slate-400 dark:bg-slate-500 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                        <div className="w-1.5 h-7 bg-slate-400 dark:bg-slate-500 rounded-full animate-bounce" style={{ animationDelay: '0.3s' }}></div>
                        <div className="w-1.5 h-3 bg-slate-400 dark:bg-slate-500 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
                    </div>
                    <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400 dark:text-slate-500">Audio Visualizer</span>
                </div>
            )}
        </div>
    );
};
]]></content>
</change>

