                        aria-label={isSaved ? 'Changes saved successfully' : 'Save changes to voice profile'}
                        className={`flex items-center gap-2 px-3.5 py-1.5 text-[10px] font-bold uppercase tracking-wide rounded-lg transition-all duration-300 border
                        ${isSaved 
