                            ? 'bg-emerald-50 text-emerald-600 border-emerald-200 dark:bg-emerald-900/20 dark:text-emerald-400 dark:border-emerald-800' 
                            : hasUnsavedChanges 
                                ? 'bg-indigo-600 text-white border-indigo-600 hover:bg-indigo-500 shadow-sm' 
                                : 'bg-slate-50 dark:bg-white/5 text-slate-400 dark:text-slate-500 border-slate-200 dark:border-white/10 cursor-not-allowed'
                        }`}>
                        {isSaved ? <CheckCircleIcon className="w-3.5 h-3.5" /> : <SaveIcon className="w-3.5 h-3.5" />}
                        <span>{isSaved ? 'Saved' : 'Save'}</span>
                    </button>
                </div>

                <label htmlFor="voice-description" className="block text-[10px] font-bold uppercase tracking-widest text-slate-500 dark:text-slate-400 mb-3">Description</label>
                <textarea id="voice-description" rows={3} className="w-full bg-slate-50 dark:bg-black/20 rounded-xl border border-slate-200 dark:border-white/10 focus:ring-2 focus:ring-indigo-500/20 dark:focus:ring-indigo-400/20 focus:border-indigo-500 dark:focus:border-indigo-400 transition-all text-sm p-4 placeholder:text-slate-400 resize-none text-slate-700 dark:text-slate-200 leading-relaxed" placeholder="E.g., A deep, calm male monk for meditation guides" value={localDescription} onChange={(e) => setLocalDescription(e.target.value)} />
            </div>

            <div className="relative" ref={vibeMenuRef}>
                <label className="block text-[10px] font-bold uppercase tracking-widest text-slate-500 dark:text-slate-400 mb-3">Personality / Vibe</label>
                <button 
